import React, { useEffect, useState } from "react";
import axios from "axios";

const Dashboard = () => {
  const [jobs, setJobs] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5000/api/jobs/all")
      .then(res => setJobs(res.data));
  }, []);

  return (
    <div>
      <h2>Jobs</h2>

      {jobs.map(job => (
        <div key={job._id}>
          <h4>{job.title}</h4>
          <p>{job.status}</p>
        </div>
      ))}

    </div>
  );
};

export default Dashboard;
